from fastapi import FastAPI, BackgroundTasks
import logging
import time
import traceback

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = FastAPI()


# Strategy 1: Try/except with structured logging
def send_notification(user_id: int, message: str):
    try:
        # Simulate an API call that might fail
        if user_id == 0:
            raise ConnectionError("Notification service unavailable")
        logger.info(f"Notification sent to user {user_id}")
    except Exception:
        logger.error(
            "Background task failed",
            extra={
                "task": "send_notification",
                "user_id": user_id,
                "traceback": traceback.format_exc(),
            },
        )


# Strategy 2: Retry with exponential backoff
def send_email_with_retry(
    to: str,
    subject: str,
    max_retries: int = 3,
):
    for attempt in range(max_retries):
        try:
            # Simulate email sending
            if attempt < 2:
                raise ConnectionError("SMTP timeout")
            logger.info(f"Email sent to {to}: {subject}")
            return  # Success
        except ConnectionError as e:
            wait = 2 ** attempt  # 1s, 2s, 4s
            logger.warning(
                f"Attempt {attempt + 1}/{max_retries} failed: {e}. "
                f"Retrying in {wait}s..."
            )
            time.sleep(wait)
    # All retries exhausted
    logger.error(f"Failed to send email to {to} after {max_retries} attempts")


# Strategy 3: Generic safe wrapper
def safe_background_task(func, *args, **kwargs):
    """Wraps any function with error handling."""
    try:
        result = func(*args, **kwargs)
        logger.info(f"Task {func.__name__} completed successfully")
        return result
    except Exception:
        logger.error(
            f"Task {func.__name__} failed: {traceback.format_exc()}"
        )


def risky_calculation(x: int):
    return 100 / x  # Might raise ZeroDivisionError


@app.post("/process/{user_id}")
async def process_user(
    user_id: int,
    background_tasks: BackgroundTasks,
):
    background_tasks.add_task(send_notification, user_id, "Processing")
    background_tasks.add_task(
        send_email_with_retry, "admin@example.com", "Report"
    )
    background_tasks.add_task(
        safe_background_task, risky_calculation, user_id
    )
    return {"user_id": user_id, "status": "processing"}

