from typing import Annotated
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = FastAPI()


# --- 1. Dependency that adds background tasks ---
def audit_log_dep(background_tasks: BackgroundTasks):
    """Dependency that schedules an audit log task."""
    def log_action(action: str):
        logger.info(f"AUDIT: {action}")

    background_tasks.add_task(log_action, "endpoint_accessed")
    return "audit_enabled"

@app.get("/items")
async def list_items(
    audit: Annotated[str, Depends(audit_log_dep)],
    background_tasks: BackgroundTasks,
):
    # This task runs AFTER the dependency's task
    background_tasks.add_task(logger.info, "items listed")
    return {"items": [], "audit": audit}


