# --- 3. RIGHT: Background task creates its own resources ---
class FakeDB:
    def __init__(self):
        self.connected = True
    def close(self):
        self.connected = False
    def query(self, sql: str):
        return f"Result of: {sql}"

def get_db_factory():
    """Returns a factory, not a session."""
    def create_db():
        return FakeDB()
    return create_db

def background_process(item_id: int):
    """Background task creates its own DB session."""
    db = FakeDB()
    try:
        result = db.query(f"UPDATE items SET status='processed' WHERE id={item_id}")
        logger.info(f"Background: {result}")
    finally:
        db.close()

@app.post("/items/{item_id}/process")
async def process_item(
    item_id: int,
    background_tasks: BackgroundTasks,
):
    background_tasks.add_task(background_process, item_id)
    return {"item_id": item_id, "status": "processing"}


# --- 4. Class-based dependency with background tasks ---
class NotificationService:
    def __init__(self, background_tasks: BackgroundTasks):
        self.background_tasks = background_tasks

    def schedule_email(self, to: str, subject: str):
        self.background_tasks.add_task(
            self._send_email, to, subject
        )

    @staticmethod
    def _send_email(to: str, subject: str):
        logger.info(f"Email to {to}: {subject}")

@app.post("/users/{user_id}/welcome")
async def welcome_user(
    user_id: int,
    notifier: Annotated[NotificationService, Depends()],
):
    notifier.schedule_email(f"user{user_id}@example.com", "Welcome!")
    return {"user_id": user_id, "status": "welcomed"}

